import datetimefrom dataclasses import dataclassfrom app.repository.checkins import CheckinsRepository@dataclassclass CheckinsService:	checkin_repo: CheckinsRepository			def set_checkin(self, habit_id: int) -> None:		self.checkin_repo.set_checkin(habit_id=habit_id)			def delete_checkin(self, habit_id: int, date: str):		date = datetime.datetime.strptime(date, "%Y-%m-%d")		self.checkin_repo.delete_checkin(habit_id=habit_id, date=date)		